    71→        {hasVehicleInfo && (
    72→          <>
    73→            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
    74→              Tag
    75→            </Text>
    76→            <Text type="paragraphMD" color="INTENSE_COLOR_03">
    77→              {vehicleInfo}
    78→            </Text>
    79→            {renderDivider()}
    80→          </>
    81→        )}
    82→
    83→        {hasPurchaseTypeLabel && (
    84→          <>
    85→            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
    86→              Tipo de compra
    87→            </Text>
    88→            <Text type="paragraphMD" color="INTENSE_COLOR_03">
    89→              {purchaseTypeLabel}
    90→            </Text>
    91→          </>
    92→        )}
    93→      </>
    94→    );
    95→  };
